# The 9 well-known device categories already encoded in
# ``VendorModel.DeviceCategory``. We seed them as DeviceType rows so a
# freshly-migrated DB already carries the canonical catalogue and existing
# VendorModel rows can auto-link via the matching ``device_type`` charfield.
# Only mechanical metadata (label + icon) — no offline windows, no field
# mappings, no controllable flags. Operators populate that content per type
# when they're ready.
SEED_DEVICE_TYPES = [
    ("water_meter",         "Water Meter",          "droplet"),
    ("gas_meter",           "Gas Meter",            "flame"),
    ("heat_meter",          "Heat Meter",           "thermometer"),
    ("heat_cost_allocator", "Heat Cost Allocator",  "calculator"),
    ("power_meter",         "Power Meter",          "zap"),
    ("environment_sensor",  "Environment Sensor",   "gauge"),
    ("thermostat_head",     "Thermostat Head",      "thermometer-sun"),
    ("smart_plug",          "Smart Plug",           "plug"),
    ("gateway",             "Gateway",              "router"),
]


def seed_types_and_backfill(apps, schema_editor):
    DeviceType = apps.get_model("library", "DeviceType")
    VendorModel = apps.get_model("library", "VendorModel")

    code_to_id = {}
    for code, label, icon in SEED_DEVICE_TYPES:
        obj, _ = DeviceType.objects.get_or_create(
            code=code,
            defaults={"label": label, "icon": icon},
        )
        code_to_id[code] = obj.id

    # The legacy ``device_type`` CharField already carries the right enum
    # value — we just translate it into the FK.
    for code, dt_id in code_to_id.items():
        VendorModel.objects.filter(
            device_type=code, device_type_fk__isnull=True,
        ).update(device_type_fk=dt_id)


def unseed_types_and_clear_backfill(apps, schema_editor):
    """Reverse: clear FKs and remove the seeded rows. Skip rows the operator
    edited (i.e. anything outside our seed code list)."""
    DeviceType = apps.get_model("library", "DeviceType")
    VendorModel = apps.get_model("library", "VendorModel")

    seed_codes = [code for code, _, _ in SEED_DEVICE_TYPES]
    VendorModel.objects.filter(
        device_type_fk__code__in=seed_codes,
    ).update(device_type_fk=None)
    DeviceType.objects.filter(code__in=seed_codes).delete()


